CREATE TABLE t_p4323659_dark_music_stream.tracks (id SERIAL PRIMARY KEY, title VARCHAR(200) NOT NULL, artist VARCHAR(200) NOT NULL, album VARCHAR(200), genre VARCHAR(100), duration INTEGER DEFAULT 0, cover_url TEXT, audio_url TEXT, plays INTEGER DEFAULT 0, user_id INTEGER REFERENCES t_p4323659_dark_music_stream.users(id), is_demo BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT NOW());